    46	static int read_slice_info(const F1AP_ServedPLMNs_Item_t *plmn, nssai_t *nssai, int max_nssai)
    47	{
    48	  if (plmn->iE_Extensions == NULL)
    49	    return 0;
    50	
    51	  const F1AP_ProtocolExtensionContainer_10696P34_t *p = (F1AP_ProtocolExtensionContainer_10696P34_t *)plmn->iE_Extensions;
    52	  if (p->list.count == 0)
    53	    return 0;
    54	
    55	  const F1AP_ServedPLMNs_ItemExtIEs_t *splmn = p->list.array[0];
    56	  DevAssert(splmn->id == F1AP_ProtocolIE_ID_id_TAISliceSupportList);
    57	  DevAssert(splmn->extensionValue.present == F1AP_ServedPLMNs_ItemExtIEs__extensionValue_PR_SliceSupportList);
    58	  const F1AP_SliceSupportList_t *ssl = &splmn->extensionValue.choice.SliceSupportList;
    59	  AssertFatal(ssl->list.count <= max_nssai, "cannot handle more than 16 slices\n");
    60	  for (int s = 0; s < ssl->list.count; ++s) {
    61	    const F1AP_SliceSupportItem_t *sl = ssl->list.array[s];
    62	    nssai_t *n = &nssai[s];
    63	    OCTET_STRING_TO_INT8(&sl->sNSSAI.sST, n->sst);
    64	    n->sd = 0xffffff;
    65	    if (sl->sNSSAI.sD != NULL)
    66	      OCTET_STRING_TO_INT24(sl->sNSSAI.sD, n->sd);
    67	  }
    68	
    69	  return ssl->list.count;
    70	}
